#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char dish1[4][11], dish2[4][11];
        for (int i = 0; i < 4; i++) scanf("%s", dish1[i]);
        for (int i = 0; i < 4; i++) scanf("%s", dish2[i]);
        int common = 0;
        for (int i = 0; i < 4; i++) {
            for (int j = 0; j < 4; j++) {
                if (strcmp(dish1[i], dish2[j]) == 0) common++;
            }
        }
        if (common >= 2) printf("similar\n");
        else printf("dissimilar\n");
    }
    return 0;
}

