import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String[] dish1 = new String[4];
            String[] dish2 = new String[4];
            for (int i = 0; i < 4; i++) dish1[i] = sc.next();
            for (int i = 0; i < 4; i++) dish2[i] = sc.next();
            int common = 0;
            for (int i = 0; i < 4; i++) {
                for (int j = 0; j < 4; j++) {
                    if (dish1[i].equals(dish2[j])) common++;
                }
            }
            if (common >= 2) System.out.println("similar");
            else System.out.println("dissimilar");
        }
    }
}

